const items = $input.all();
const entries = items[0].json.rss.channel[0].item || [];

// Get random 3 topics for today's videos
const shuffled = entries.sort(() => 0.5 - Math.random());
const selected = shuffled.slice(0, 3);

return selected.map(item => ({
  json: {
    topic: item.title[0],
    description: item.description ? item.description[0] : '',
    link: item.link ? item.link[0] : ''
  }
}));

const response = $input.item.json;
const script = response.response;
const topic = $('Select Topics').item.json.topic;

// Generate title
const title = topic.substring(0, 80);

// Extract keywords for image search
const keywords = topic.split(' ').slice(0, 3).join(' ');

// Generate hashtags
const words = topic.toLowerCase().split(' ');
const hashtags = words.slice(0, 5).map(w => '#' + w.replace(/[^a-z0-9]/g, '')).join(' ');

return {
  json: {
    topic: topic,
    title: title,
    script: script,
    keywords: keywords,
    hashtags: hashtags,
    timestamp: new Date().getTime()
  }
};

const photos = $input.item.json.photos || [];
const scriptData = $('Process Script').item.json;

if (photos.length === 0) {
  throw new Error('No images found');
}

// Download images
const imageUrls = photos.slice(0, 5).map(p => p.src.large);

return {
  json: {
    ...scriptData,
    image_urls: imageUrls,
    num_images: imageUrls.length
  }
};

const https = require('https');
const fs = require('fs');
const path = require('path');

const data = $input.item.json;
const imageUrls = data.image_urls;
const timestamp = data.timestamp;
const baseDir = 'C:\\youtube_automation\\images';

// Download images synchronously
const downloadedImages = [];

for (let i = 0; i < imageUrls.length; i++) {
  const url = imageUrls[i];
  const filename = path.join(baseDir, `img_${timestamp}_${i}.jpg`);

  // Simple sync download (for n8n compatibility)
  const file = fs.createWriteStream(filename);

  await new Promise((resolve, reject) => {
    https.get(url, (response) => {
      response.pipe(file);
      file.on('finish', () => {
        file.close();
        downloadedImages.push(filename);
        resolve();
      });
    }).on('error', reject);
  });
}

return {
  json: {
    ...data,
    audio_file: `C:\\youtube_automation\\audio\\audio_${timestamp}.mp3`,
    image_files: downloadedImages,
    output_file: `C:\\youtube_automation\\videos\\video_${timestamp}.mp4`
  }
};

const prevData = $('Download Images').item.json;
const videoResult = JSON.parse($input.item.json.stdout);

const description = `${prevData.script}\n\n${prevData.hashtags}\n\nCreated with AI`;
const tags = prevData.hashtags.split(' ').map(t => t.replace('#', '')).filter(t => t.length > 0);

return {
  json: {
    video_file: videoResult.video_path,
    title: prevData.title,
    description: description,
    tags: tags
  }
};

const result = JSON.parse($input.item.json.stdout);

return {
  json: {
    success: true,
    video_url: result.url,
    video_id: result.video_id,
    title: result.title,
    uploaded_at: new Date().toISOString()
  }
};
